sql:
SELECT profile_name
FROM demographic_profiles
WHERE age_range = '40-55' AND occupation_id = 1 AND is_active = 1;

SELECT COUNT(*) AS total_profiles
FROM demographic_profiles
WHERE is_active = 1;

SELECT profile_name
FROM demographic_profiles
WHERE profile_id = 1;

external_knowledge:
External knowledge: 'Age brackets' are defined as '0-20', '21-40', '41-60', and '60+';
'Income categories' are based on the income_ranges (e.g., 0-25K, 25K-50K);
'Native countries' refers specifically to the United States and Canada.
